keyframes_css:
@keyframes flicker {
  0% { transform: translateY(0) scaleY(1); opacity: 0.8; }
  25% { transform: translateY(-2px) scaleY(1.1); opacity: 0.9; }
  50% { transform: translateY(-1px) scaleY(0.95); opacity: 0.7; }
  75% { transform: translateY(-3px) scaleY(1.05); opacity: 0.85; }
  100% { transform: translateY(0) scaleY(1); opacity: 0.8; }
}

@keyframes rise {
  0% { transform: translateY(0); opacity: 1; }
  100% { transform: translateY(-40px); opacity: 0; }
}

.demo-stage {
  background: #ffffff;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 8px;
  padding: 20px;
}

.demo-stage .flame {
  width: 24px;
  height: 40px;
  background: linear-gradient(180deg, #f5c9d4 0%, #e8b4c4 50%, #d4a5b8 100%);
  border-radius: 50% 50% 40% 40%;
  animation: flicker 1.6s ease-in-out infinite;
}

.demo-stage .flame:nth-child(2) {
  animation-delay: 0.2s;
  background: linear-gradient(180deg, #f0e0c0 0%, #e8d0b0 50%, #d4b8a0 100%);
}

.demo-stage .flame:nth-child(3) {
  animation-delay: 0.4s;
  background: linear-gradient(180deg, #f5c9d4 0%, #e8b4c4 50%, #d4a5b8 100%);
}

.demo-stage .spark {
  position: absolute;
  width: 6px;
  height: 6px;
  background: #f0e0c0;
  border-radius: 50%;
  animation: rise 2s ease-out infinite;
  opacity: 0;
}

.demo-stage .spark:nth-child(4) {
  left: 70px;
  bottom: 60px;
  animation-delay: 0s;
}

.demo-stage .spark:nth-child(5) {
  left: 100px;
  bottom: 60px;
  animation-delay: 0.6s;
}

@keyframes wave {
  0% { transform: translateX(0) translateY(0); }
  25% { transform: translateX(0) translateY(-8px); }
  50% { transform: translateX(0) translateY(0); }
  75% { transform: translateX(0) translateY(8px); }
  100% { transform: translateX(0) translateY(0); }
}

.demo-stage {
  background: #ffffff;
  width: 200px;
  height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
}

.demo-stage > div {
  width: 12px;
  height: 60px;
  background: #c9dff5;
  border-radius: 6px;
  animation: wave 1.2s ease-in-out infinite;
}

.demo-stage > div:nth-child(2) {
  animation-delay: 0.1s;
}

.demo-stage > div:nth-child(3) {
  animation-delay: 0.2s;
}

.demo-stage > div:nth-child(4) {
  animation-delay: 0.3s;
}

.demo-stage > div:nth-child(5) {
  animation-delay: 0.4s;
}

@keyframes cicada-pulse {
  0% {
    transform: scale(1);
    opacity: 1;
  }
  50% {
    transform: scale(1.1);
    opacity: 0.7;
  }
  100% {
    transform: scale(1);
    opacity: 1;
  }
}

@keyframes wing-flutter {
  0% {
    transform: rotateZ(-2deg);
  }
  50% {
    transform: rotateZ(2deg);
  }
  100% {
    transform: rotateZ(-2deg);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: #ffffff;
  display: flex;
  align-items: center;
  justify-content: center;
}

.demo-stage .cicada-body {
  width: 60px;
  height: 80px;
  background: linear-gradient(135deg, #d4d4d4 0%, #b0b0b0 100%);
  border-radius: 50% 50% 45% 45%;
  position: relative;
  animation: cicada-pulse 1.2s ease-in-out infinite;
}

.demo-stage .cicada-body::before {
  content: '';
  position: absolute;
  width: 50px;
  height: 60px;
  background: #f5c9d4;
  border-radius: 50% 50% 40% 40%;
  top: 10px;
  left: 5px;
  opacity: 0.6;
  animation: wing-flutter 0.3s ease-in-out infinite;
}

@keyframes flicker {
  0%, 100% { transform: translateY(0) scaleY(1); opacity: 0.8; }
  25% { transform: translateY(-8px) scaleY(1.1); opacity: 0.9; }
  50% { transform: translateY(-4px) scaleY(0.95); opacity: 0.7; }
  75% { transform: translateY(-6px) scaleY(1.05); opacity: 0.85; }
}

@keyframes rise {
  0% { transform: translateY(0); opacity: 1; }
  100% { transform: translateY(-40px); opacity: 0; }
}

.demo-stage {
  background: #ffffff;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  overflow: hidden;
}

.demo-stage .flame-core {
  width: 24px;
  height: 32px;
  background: linear-gradient(to top, #f5c9d4 0%, #f0e0c0 100%);
  border-radius: 50% 50% 40% 40%;
  animation: flicker 1.2s ease-in-out infinite;
  position: relative;
}

.demo-stage .flame-core::before {
  content: '';
  position: absolute;
  width: 16px;
  height: 24px;
  background: #f0e0c0;
  border-radius: 50% 50% 30% 30%;
  top: -8px;
  left: 4px;
  animation: flicker 1.4s ease-in-out infinite 0.1s;
}

.demo-stage .spark {
  position: absolute;
  width: 4px;
  height: 4px;
  background: #f5c9d4;
  border-radius: 50%;
  animation: rise 1.6s ease-out infinite;
}

.demo-stage .spark:nth-child(2) {
  left: 8px;
  animation-delay: 0.3s;
}

.demo-stage .spark:nth-child(3) {
  left: -8px;
  animation-delay: 0.6s;
}

@keyframes flicker {
  0% { transform: translateY(0) scaleY(0.8); opacity: 0.6; }
  50% { transform: translateY(-8px) scaleY(1.1); opacity: 0.9; }
  100% { transform: translateY(0) scaleY(0.8); opacity: 0.6; }
}

@keyframes sway {
  0%, 100% { transform: translateX(0); }
  50% { transform: translateX(3px); }
}

.demo-stage {
  background-color: #ffffff;
  width: 200px;
  height: 200px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  padding: 20px;
}

.demo-stage::before {
  content: '';
  width: 30px;
  height: 50px;
  background: linear-gradient(to top, #f5c9d4, #f0e0c0);
  border-radius: 50% 50% 40% 40%;
  animation: flicker 1.5s ease-in-out infinite, sway 2s ease-in-out infinite;
  filter: blur(2px);
}

.demo-stage::after {
  content: '';
  width: 20px;
  height: 35px;
  background: linear-gradient(to top, #f0e0c0, rgba(245, 201, 212, 0.3));
  border-radius: 50% 50% 30% 30%;
  position: absolute;
  animation: flicker 1.2s ease-in-out infinite 0.2s, sway 2.5s ease-in-out infinite 0.3s;
  filter: blur(3px);
  margin-left: 15px;
}

@keyframes wave {
  0% {
    transform: translateX(0) translateY(0);
  }
  25% {
    transform: translateX(20px) translateY(-12px);
  }
  50% {
    transform: translateX(40px) translateY(0);
  }
  75% {
    transform: translateX(20px) translateY(12px);
  }
  100% {
    transform: translateX(0) translateY(0);
  }
}

.demo-stage {
  background: #ffffff;
  width: 200px;
  height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.demo-stage .wave-line {
  width: 80px;
  height: 3px;
  background: #c9dff5;
  border-radius: 2px;
  animation: wave 1.6s ease-in-out infinite;
}

.demo-stage .wave-dot {
  width: 12px;
  height: 12px;
  background: #d4e8d0;
  border-radius: 50%;
  position: absolute;
  animation: wave 1.6s ease-in-out infinite;
  opacity: 0.7;
}

.demo-stage .wave-dot:nth-child(2) {
  animation-delay: 0.3s;
}

.demo-stage .wave-dot:nth-child(3) {
  animation-delay: 0.6s;
}
